export interface PracticeMove {
  move: string;
  explanation: string;
}

export interface Lesson {
  id: string;
  title: string;
  content: string;
  keyPoints: string[];
  fen?: string;
  practiceLine?: {
    startFen?: string;
    playerColor: "w" | "b";
    moves: PracticeMove[];
    autoResponses: string[];
    completionMessage: string;
  };
}

export type CourseCategory = "basics" | "openings" | "tactics" | "middlegame" | "endgame" | "strategy" | "mindset";

export type CourseTier = "free" | "premium";

export interface Course {
  id: string;
  title: string;
  description: string;
  level: "Beginner" | "Intermediate" | "Advanced";
  icon: string;
  category?: CourseCategory;
  tier: CourseTier;
  lessons: Lesson[];
}

function L(id: string, title: string, content: string, keyPoints: string[], fen?: string): Lesson {
  return { id, title, content, keyPoints, fen };
}

